3. 可空布尔类型（Nullable） <pre><code>// bool? 表示可空的布尔类型（三态逻辑）
bool? isApproved = null;  // 既不是true也不是false，表示"未知"或"未决定"

// 使用场景：问卷调查中用户可能跳过的问题
bool? answer1 = true;     // 是
bool? answer2 = false;    // 否
bool? answer3 = null;     // 未回答

// 检查可空布尔值
if (isApproved.HasValue)
{
    Console.WriteLine($"审批状态：{isApproved.Value}");
}
else
{
    Console.WriteLine("审批状态：待定");
}

// 使用空值合并运算符
bool definiteResult = isApproved ?? false;  // 如果为null则返回false
Console.WriteLine($"确定的结果：{definiteResult}");

// 可空布尔的三态逻辑
bool?[] surveyAnswers = { true, false, null, true, null };
int trueCount = 0, falseCount = 0, nullCount = 0;

foreach (var answer in surveyAnswers)
{
    if (answer == true) trueCount++;
    else if (answer == false) falseCount++;
    else nullCount++;
}

Console.WriteLine($"调查结果：是={trueCount}, 否={falseCount}, 未回答={nullCount}");
</code></pre>

错误1：误用赋值运算符 <pre><code>int score = 85;
bool isPassing;

// ❌ 常见错误：使用单个等号（赋值）
// if (isPassing = score &gt;= 60)  // 这会将比较结果赋值给isPassing，然后检查isPassing
// {
//     Console.WriteLine("及格");
// }

// ✅ 正确：使用双等号（比较）
if (score &gt;= 60)
{
    isPassing = true;
    Console.WriteLine("及格");
}
else
{
    isPassing = false;
}

// 或者直接赋值
isPassing = (score &gt;= 60);
</code></pre>

错误2：不必要的比较 <pre><code>bool isReady = true;

// ❌ 不必要的比较
// if (isReady == true)
// {
//     // 执行操作
// }

// ✅ 直接使用布尔值
if (isReady)
{
    Console.WriteLine("准备好了");
}

// 对于false也是类似
// if (isReady == false)  // ❌ 不好
// if (!isReady)          // ✅ 好
</code></pre>

错误3：混淆布尔与数值 <pre><code>int count = 0;
bool hasItems;

// ❌ 错误：试图用数值表示布尔
// hasItems = count;  // 编译错误

// ✅ 正确：显式转换
hasItems = count &gt; 0;  // 如果count大于0，则hasItems为true

// 或者使用Convert
hasItems = Convert.ToBoolean(count);  // 0→false，非0→true

Console.WriteLine($"count={count}, hasItems={hasItems}");
</code></pre>

练习1：温度警报系统 <pre><code>// 创建一个温度监控系统
// 要求：
// 1. 如果温度高于30°C，发出高温警报
// 2. 如果温度低于0°C，发出低温警报
// 3. 如果温度在正常范围，显示正常

double temperature = 25.5;
bool isHighTemp = temperature &gt; 30;
bool isLowTemp = temperature &lt; 0;
bool isNormalTemp = !isHighTemp &amp;&amp; !isLowTemp;

Console.WriteLine($"当前温度：{temperature}°C");
Console.WriteLine($"高温警报：{isHighTemp}");
Console.WriteLine($"低温警报：{isLowTemp}");
Console.WriteLine($"温度正常：{isNormalTemp}");
</code></pre>

练习2：密码强度检查器 <pre><code>// 检查密码强度
// 要求：
// 1. 至少8个字符
// 2. 包含大写字母
// 3. 包含小写字母
// 4. 包含数字
// 5. 密码强度为高需要满足所有条件

string password = "Pass1234";
bool hasMinLength = password.Length &gt;= 8;
bool hasUpperCase = password.Any(char.IsUpper);
bool hasLowerCase = password.Any(char.IsLower);
bool hasDigit = password.Any(char.IsDigit);
bool isStrongPassword = hasMinLength &amp;&amp; hasUpperCase &amp;&amp; hasLowerCase &amp;&amp; hasDigit;

Console.WriteLine("密码强度检查：");
Console.WriteLine($"长度≥8：{hasMinLength}");
Console.WriteLine($"有大写字母：{hasUpperCase}");
Console.WriteLine($"有小写字母：hasLowerCase");
Console.WriteLine($"有数字：{hasDigit}");
Console.WriteLine($"强密码：{isStrongPassword}");
</code></pre>

3. 可空类型（Nullable）转换 <pre><code>// 基础类型↔可空类型
int normal = 100;
int? nullable = normal;       // 隐式：int → int?
int back = nullable.Value;    // 需要.Value（可能抛异常）

// 安全访问
int safeValue = nullable ?? 0;  // 如果null则返回0

// 可空类型间的转换
int? nullableInt = 100;
long? nullableLong = nullableInt;  // 隐式：int? → long?
</code></pre>

4. checked/unchecked上下文 <pre><code>// 默认：unchecked（不检查算术溢出）
int max = int.MaxValue;
int overflow = max + 1;  // 变成int.MinValue，不报错

// checked：严格检查
checked
{
    // int error = max + 1;  // 编译时/运行时异常
}

// 项目级设置
// 在.csproj中添加：&lt;CheckForOverflowUnderflow&gt;true&lt;/CheckForOverflowUnderflow&gt;
</code></pre>

黄金法则 <pre><code>// 法则1：优先隐式转换（最安全）
int small = 100;
long big = small;  // ✅ 推荐

// 法则2：字符串用TryParse
string input = "123";
if (int.TryParse(input, out int result)) { }

// 法则3：显式转换要检查范围
long source = 5000000000L;
if (source &gt;= int.MinValue &amp;&amp; source &lt;= int.MaxValue)
{
    int target = (int)source;
}

// 法则4：财务计算用decimal
decimal price = 19.99m;
decimal total = price * 3;  // 59.97m（精确）

// 法则5：浮点转换注意精度
float f = 0.1f;
double d = f;  // 可能不是精确的0.1
</code></pre>

常见错误避免 <pre><code>// ❌ 错误1：忽略浮点精度
float f1 = 0.1f;
float f2 = 0.2f;
float sum = f1 + f2;  // 可能不是0.3

// ✅ 正确：用decimal或比较时用容差
const float epsilon = 0.00001f;
if (Math.Abs(sum - 0.3f) &lt; epsilon) { }

// ❌ 错误2：未处理可能为null的值
int? nullableValue = GetFromDatabase();
int value = nullableValue.Value;  // 如果null则异常

// ✅ 正确：使用空值合并运算符
int safeValue = nullableValue ?? 0;

// ❌ 错误3：混淆除法的类型
int a = 5, b = 2;
int result = a / b;  // 2（整数除法）

// ✅ 正确：需要小数时转换类型
double correct = (double)a / b;  // 2.5
</code></pre>

性能优化建议 <pre><code>// 1. 循环内避免重复转换
for (int i = 0; i &lt; 1000000; i++)
{
    // ❌ 不好：每次循环都转换
    // float value = (float)i;

    // ✅ 好：预先转换或改变循环变量类型
}

// 2. 使用合适的类型减少转换
List&lt;int&gt; intList = new List&lt;int&gt;();  // 泛型，无装箱
ArrayList oldList = new ArrayList();  // 非泛型，需要装箱拆箱

// 3. 使用Span&lt;T&gt;处理大量数据转换
byte[] bytes = new byte[1000];
Span&lt;int&gt; ints = MemoryMarshal.Cast&lt;byte, int&gt;(bytes);
</code></pre>

