特性 break continue 作用 完全终止循环 跳过本次迭代，继续下一次循环 循环状态 循环结束 循环继续 后续代码 执行循环后的代码 继续执行循环的下一次迭代 <pre><code>// 对比示例
Console.WriteLine("break 示例：");
for (int i = 1; i &lt;= 5; i++)
{
    if (i == 3)
    {
        break;  // 当i=3时，整个循环结束
    }
    Console.WriteLine(i);
}
// 输出：1, 2

Console.WriteLine("\ncontinue 示例：");
for (int i = 1; i &lt;= 5; i++)
{
    if (i == 3)
    {
        continue;  // 当i=3时，跳过本次，继续i=4
    }
    Console.WriteLine(i);
}
// 输出：1, 2, 4, 5
</code></pre>

